sub extract_metadata {
    my ($pdf) = @_;
    my $info = $pdf->info;
    return {
        author => $info->Author,
        title  => $info->Title,
        date   => $info->CreationDate,
    };
}

# Function to extract tables from the PDF
sub extract_tables {
    my ($pdf) = @_;
    my @tables;
    my $page_count = $pdf->pages->count;

    for my $page (1 .. $page_count) {
        my $page_obj = $pdf->openpage($page);
        my $text = $page_obj->textout(0, 0, 0, 0, 0);
        push @tables, $text if $text =~ /Table/;
    }

    return @tables;
}

